configuration.jsScript:
function validateData(msg, metadata) {
    metadata.checkValidator = "true"; // Mặc định là đúng
    var p = msg.params;

    // --- 1. KIỂM TRA CÁC TRƯỜNG CƠ BẢN (CODE 1) ---
    if (typeof p.entityName_Project !== 'string') {
        metadata.checkValidator = "false";
        return { code: 1, message: "Thiếu hoặc sai kiểu dữ liệu key 'entityName_Project'" };
    }
    if (typeof p.entityName_Rule !== 'string') {
        metadata.checkValidator = "false";
        return { code: 1, message: "Thiếu hoặc sai kiểu dữ liệu key 'entityName_Rule'" };
    }
    if (typeof p.name !== 'string') {
        metadata.checkValidator = "false";
        return { code: 1, message: "Thiếu hoặc sai kiểu dữ liệu key 'name'" };
    }
    if (typeof p.type !== 'string') {
        metadata.checkValidator = "false";
        return { code: 1, message: "Thiếu hoặc sai kiểu dữ liệu key 'type'" };
    }
    if (typeof p.status !== 'boolean') {
        metadata.checkValidator = "false";
        return { code: 1, message: "Thiếu hoặc sai kiểu dữ liệu key 'status'" };
    }

    // --- 2. KIỂM TRA VALIDITYPERIOD (CODE 2) ---
    var vp = p.validityPeriod;
    if (!vp) {
        metadata.checkValidator = "false";
        return { code: 2, message: "validityPeriod không tồn tại" };
    }
    if (typeof vp.allDay !== 'boolean') {
        metadata.checkValidator = "false";
        return { code: 2, message: "Key 'allDay' trong validityPeriod sai định dạng" };
    }
    if (typeof vp.startDay !== 'number') {
        metadata.checkValidator = "false";
        return { code: 2, message: "Key 'startDay' trong validityPeriod sai định dạng" };
    }
    if (typeof vp.endDay !== 'number') {
        metadata.checkValidator = "false";
        return { code: 2, message: "Key 'endDay' trong validityPeriod sai định dạng" };
    }

    // 4. Kiểm tra inputData & Triggers
    var inData = p.inputData;
    if (!inData) {
        metadata.checkValidator = "false";
        return { code: 3, message: "inputData không tồn tại" };
    }
    if (typeof inData.logic !== 'string') {
        metadata.checkValidator = "false";
        return { code: 3, message: "Thiếu hoặc sai kiểu dữ liệu của key 'logic'"};
    }
    if (!inData.inputTimer) {
        metadata.checkValidator = "false";
        return { code: 3, message: "inputTimer không tồn tại " };
    }
    if (typeof inData.inputTimer.activeTimer !== 'boolean') {
        metadata.checkValidator = "false";
        return { code: 3, message: "Thiếu hoặc sai kiểu dữ liệu của key 'activeTimer'"};
    }    
    var triggers = inData.inputTimer.triggers;
    if (!(triggers instanceof Array)) {
        metadata.checkValidator = "false";
        return { code: 3, message: "mảng thời gian kích hoạt bị lỗi cấu trúc hoặc không tồn tại" };
    }
    for (var i = 0; i < triggers.length; i++) {
        var t = triggers[i];
        if (typeof t.time !== 'string' || typeof t.repeat !== 'number' || t.repeat < 0 || t.repeat > 127) {
            metadata.checkValidator = "false";
            return { code: 3, message: "Phần tử Trigger  thứ " + i + "lỗi" };
        }
    }

    // --- 4. KIỂM TRA LISTINPUTDEVICE (CODE 4) ---
    var inDevs = inData.listInputDevice;
    if (!(inDevs instanceof Array)) {
        metadata.checkValidator = "false";
        return { code: 4, message: "listInputDevice không tồn tại hoặc sai cấu trúc mảng" };
    }

    for (var j = 0; j < inDevs.length; j++) {
        var dIn = inDevs[j];

        // Kiểm tra entityName
        if (typeof dIn.entityName !== 'string' || dIn.entityName === "") {
            metadata.checkValidator = "false";
            return { code: 4, message: "Thiếu hoặc sai entityName tại thiết bị đầu vào thứ " + j };
        }

        // Kiểm tra profileName (Dựa trên danh sách cho phép)
        var validInProfiles = ["OTHER_DEVICE"];
        if (validInProfiles.indexOf(dIn.profileName) === -1) {
            metadata.checkValidator = "false";
            return { code: 4, message: "profileName '" + dIn.profileName + "' không hợp lệ tại thiết bị thứ " + j };
        }

        // Kiểm tra mảng dataTrigger
        var dataTriggers = dIn.dataTrigger;
        if (!(dataTriggers instanceof Array)) {
            metadata.checkValidator = "false";
            return { code: 4, message: "dataTrigger tại thiết bị thứ " + j + " bị lỗi cấu trúc" };
        }

        // Kiểm tra chi tiết từng điều kiện trong dataTrigger
        for (var k = 0; k < dataTriggers.length; k++) {
            var dt = dataTriggers[k];

            if (typeof dt.key !== 'string') {
                metadata.checkValidator = "false";
                return { code: 4, message: "Thiếu 'key' tại trigger thứ " + k + " của thiết bị " + j };
            }

            // Logic kiểm tra Operator mới: =, ><, <>
            if (dt.operator === "=") {
                if (typeof dt.value === 'undefined') {
                    metadata.checkValidator = "false";
                    return { code: 4, message: "Toán tử '=' yêu cầu trường 'value' (Thiết bị " + j + ")" };
                }
            } else if (dt.operator === "><" || dt.operator === "<>") {
                if (typeof dt.min !== 'number' || typeof dt.max !== 'number') {
                    metadata.checkValidator = "false";
                    return { code: 4, message: "Toán tử '" + dt.operator + "' yêu cầu 'min' và 'max' là số (Thiết bị " + j + ")" };
                }
                if ( dt.min >= dt.max ) {
                    metadata.checkValidator = "false";
                    return { code: 4, message: "Thiêt bị đầu vào " + j + "Lỗi do min > max của điều kiện key"+ dt.key};
                }                
            } else {
                metadata.checkValidator = "false";
                return { code: 4, message: "Toán tử '" + dt.operator + "' không được hỗ trợ (Thiết bị " + j + ")" };
            }
        }
    }

    // --- 5. KIỂM TRA OUTPUTRULEVALUE (CODE 5) ---
    var outDevs = p.outputRuleValue;
    var outProfiles = ["STREET_LIGHT_RIIM", "STREET_LIGHT_CAN", "STREET_LIGHT_LAN", "GATEWAY", "BRANCH_NORMAL", "BRANCH_MESH", "BRANCH_LAN"];
    var indexTracker = {}; // Dùng object làm Map để check unique O(1)

    if (!(outDevs instanceof Array)) {
        metadata.checkValidator = "false";
        return { code: 5, message: "outputRuleValue không tồn tại hoặc sai cấu trúc mảng" };
    }

    for (var k = 0; k < outDevs.length; k++) {
        var dOut = outDevs[k];
        
        // 5.1 Kiểm tra entityName đầu ra
        if (typeof dOut.entityName !== 'string' || dOut.entityName === "") {
            metadata.checkValidator = "false";
            return { code: 5, message: "Thiếu hoặc sai entityName tại entityOutput thứ " + k };
        }

        // 5.2 Kiểm tra profileName đầu ra
        if (outProfiles.indexOf(dOut.profileName) === -1) {
            metadata.checkValidator = "false";
            return { code: 5, message: "profileName '" + dOut.profileName + "' không hợp lệ tại entityOutput thứ " + k };
        }

        // 5.3 Kiểm tra Index (phải là số và duy nhất)
        if (typeof dOut.index !== 'number') {
            metadata.checkValidator = "false";
            return { code: 5, message: "Index tại entityOutput thứ " + k + " phải là kiểu số" };
        }
        if (indexTracker[dOut.index]) {
            metadata.checkValidator = "false";
            return { code: 5, message: "Lỗi: Index " + dOut.index + " bị trùng lặp tại entityOutput thứ " + k };
        }
        indexTracker[dOut.index] = true;

        // 5.4 Kiểm tra delayOutput (0-60 giây)
        if (typeof dOut.delayOutput !== 'number' || dOut.delayOutput < 0 || dOut.delayOutput > 60) {
            metadata.checkValidator = "false";
            return { code: 5, message: "delayOutput tại entityOutput thứ " + k + " phải từ 0 đến 60" };
        }

        // 5.5 Kiểm tra dataAction (bt và dim)
        var action = dOut.dataAction;
        if (!action) {
            metadata.checkValidator = "false";
            return { code: 5, message: "Thiếu dataAction tại entityOutput thứ " + k };
        }

        // Kiểm tra bt (phải là 0 hoặc 1)
        if (typeof action.bt !== 'number' || (action.bt !== 0 && action.bt !== 1)) {
            metadata.checkValidator = "false";
            return { code: 5, message: "Trường 'bt' tại entityOutput " + k + " phải là 0 hoặc 1" };
        }

        // Kiểm tra dim (phải là số từ 0 đến 100)
        if (typeof action.dim !== 'number' || action.dim < 0 || action.dim > 100) {
            metadata.checkValidator = "false";
            return { code: 5, message: "Trường 'dim' tại entityOutput " + k + " phải từ 0 đến 100" };
        }
    }
    metadata.entityName_Project  = msg.params.entityName_Project
    metadata.entityName_Rule  = msg.params.entityName_Rule
    return msg; // Mọi thứ ok
}

// Thực thi
msg = validateData(msg, metadata);

return {
    msg: msg,
    metadata: metadata,
    msgType: msgType
};

